1	// Package serverreg provides fire-and-forget project registration with the
2	// ddx-server. CLI commands call TryRegisterAsync so the server always has an
3	// up-to-date project list. If no server is reachable the call is silently
4	// discarded — the CLI never depends on the server being available.
5	package serverreg
6	
7	import (
8		"bytes"
9		"crypto/tls"
10		"encoding/json"
11		"net/http"
12		"os"
13		"path/filepath"
14		"time"
15	)
16	
17	const defaultServerURL = "https://localhost:7743"
18	
19	// TryRegisterAsync fires off a project registration in a background goroutine
20	// and returns immediately. Errors are silently discarded.
21	func TryRegisterAsync(projectPath string) {
22		url := resolveServerURL()
23		if url == "" {
24			return
25		}
26		go register(url, projectPath)
27	}
28	
29	func register(serverURL, projectPath string) {
30		body, err := json.Marshal(map[string]string{"path": projectPath})
31		if err != nil {
32			return
33		}
34	
35		client := &http.Client{
36			Timeout: 500 * time.Millisecond,
37			// Accept self-signed certs — the server uses an auto-generated cert.
38			Transport: &http.Transport{
39				TLSClientConfig: &tls.Config{InsecureSkipVerify: true}, //nolint:gosec
40			},
41		}
42	
43		req, err := http.NewRequest(http.MethodPost, serverURL+"/api/projects/register", bytes.NewReader(body))
44		if err != nil {
45			return
46		}
47		req.Header.Set("Content-Type", "application/json")
48	
49		resp, err := client.Do(req)
50		if err != nil {
51			return
52		}
53		_ = resp.Body.Close()
54	}
55	
56	// resolveServerURL returns, in order of preference:
57	//  1. DDX_SERVER_URL environment variable
58	//  2. URL from ~/.local/share/ddx/server.addr
59	//  3. https://localhost:7743 (default)
60	func resolveServerURL() string {
61		if u := os.Getenv("DDX_SERVER_URL"); u != "" {
62			return u
63		}
64		if u := readAddrFile(); u != "" {
65			return u
66		}
67		return defaultServerURL
68	}
69	
70	func readAddrFile() string {
71		type addrFile struct {
72			URL string `json:"url"`
73		}
74		dir := addrDir()
75		data, err := os.ReadFile(filepath.Join(dir, "server.addr"))
76		if err != nil {
77			return ""
78		}
79		var af addrFile
80		if err := json.Unmarshal(data, &af); err != nil {
81			return ""
82		}
83		return af.URL
84	}
85	
86	func addrDir() string {
87		if xdg := os.Getenv("XDG_DATA_HOME"); xdg != "" {
88			return filepath.Join(xdg, "ddx")
89		}
90		home, err := os.UserHomeDir()
91		if err != nil {
92			return filepath.Join("/tmp", "ddx")
93		}
94		return filepath.Join(home, ".local", "share", "ddx")
95	}
