18	// usageRow holds aggregated stats for a single harness.
19	type usageRow struct {
20		Harness                string  `json:"harness" yaml:"harness"`
21		Sessions               int     `json:"sessions" yaml:"sessions"`
22		InputTokens            int     `json:"input_tokens" yaml:"input_tokens"`
23		OutputTokens           int     `json:"output_tokens" yaml:"output_tokens"`
24		CostUSD                float64 `json:"cost_usd" yaml:"cost_usd"`
25		CostBasis              string  `json:"cost_basis,omitempty" yaml:"cost_basis,omitempty"`
26		AvgDurationMS          float64 `json:"avg_duration_ms" yaml:"avg_duration_ms"`
27		QuotaState             string  `json:"quota_state,omitempty" yaml:"quota_state,omitempty"`
28		SignalProvider         string  `json:"signal_provider,omitempty" yaml:"signal_provider,omitempty"`
29		SignalKind             string  `json:"signal_kind,omitempty" yaml:"signal_kind,omitempty"`
30		SignalFreshness        string  `json:"signal_freshness,omitempty" yaml:"signal_freshness,omitempty"`
31		SignalBasis            string  `json:"signal_basis,omitempty" yaml:"signal_basis,omitempty"`
32		NativeInputTokens      int     `json:"native_input_tokens,omitempty" yaml:"native_input_tokens,omitempty"`
33		NativeOutputTokens     int     `json:"native_output_tokens,omitempty" yaml:"native_output_tokens,omitempty"`
34		NativeTotalTokens      int     `json:"native_total_tokens,omitempty" yaml:"native_total_tokens,omitempty"`
35		NativeSessionCount     int     `json:"native_session_count,omitempty" yaml:"native_session_count,omitempty"`
36		NativeQuotaUsedPercent int     `json:"native_quota_used_percent,omitempty" yaml:"native_quota_used_percent,omitempty"`
37	}
38	
39	type usageAgg struct {
40		sessions     int
41		inputTokens  int
42		outputTokens int
43		costUSD      float64
44		totalDurMS   int
45		costBasis    string
46	}
47	
48	type usageSessionRecord struct {
49		entry agent.SessionEntry
50		key   string
51	}
52	
53	func (a *usageAgg) addSession(entry agent.SessionEntry) {
54		a.sessions++
55		a.inputTokens += entry.InputTokens
56		a.outputTokens += entry.OutputTokens
57		a.totalDurMS += entry.Duration
58	
59		// Use recorded cost if available, else estimate from pricing table.
60		if entry.CostUSD > 0 {
61			a.costUSD += entry.CostUSD
62			a.mergeCostBasis(usageCostBasisReported)
63			return
64		}
65		if entry.Model == "" {
66			return
67		}
68		if est := agent.EstimateCost(entry.Model, entry.InputTokens, entry.OutputTokens); est >= 0 {
69			a.costUSD += est
70			if est > 0 {
71				a.mergeCostBasis(usageCostBasisEstimated)
72			}
73		}
74	}
75	
76	// localHarnesses tracks which harness names are local-only (no provider cost).
77	// Replaces the previous in-package harness lookup so this file depends on
78	// service contract metadata instead of DDx-owned harness config.
79	var localHarnesses = map[string]bool{
80		"agent":   true,
81		"virtual": true,
82		"script":  true,
83	}
84	
85	func (a *usageAgg) addOutcome(outcome agent.RoutingOutcome) {
86		a.sessions++
87		a.inputTokens += outcome.InputTokens
88		a.outputTokens += outcome.OutputTokens
89		a.totalDurMS += outcome.LatencyMS
90		if outcome.CostUSD > 0 {
91			a.costUSD += outcome.CostUSD
92			a.mergeCostBasis(usageCostBasisReported)
93			return
94		}
95		if !localHarnesses[outcome.Harness] && outcome.Model != "" {
96			if est := agent.EstimateCost(outcome.Model, outcome.InputTokens, outcome.OutputTokens); est >= 0 {
97				a.costUSD += est
98				if est > 0 {
99					a.mergeCostBasis(usageCostBasisEstimated)
100				}
101			}
102		}
103	}
104	
105	func (a *usageAgg) toRow(harness string) usageRow {
106		var avgDur float64
107		if a.sessions > 0 {
108			avgDur = float64(a.totalDurMS) / float64(a.sessions)
109		}
110		return usageRow{
111			Harness:       harness,
112			Sessions:      a.sessions,
113			InputTokens:   a.inputTokens,
114			OutputTokens:  a.outputTokens,
115			CostUSD:       a.costUSD,
116			CostBasis:     inferredUsageCostBasis(harness, a.costUSD, a.costBasis),
117			AvgDurationMS: avgDur,
118		}
119	}
120	
121	const (
122		usageCostBasisReported       = "reported"
123		usageCostBasisEstimated      = "estimated"
124		usageCostBasisEstimatedValue = "estimated_value"
125		usageCostBasisMixed          = "mixed"
126	)
127	
128	func (a *usageAgg) mergeCostBasis(basis string) {
129		if basis == "" {
130			return
131		}
132		if a.costBasis == "" {
133			a.costBasis = basis
134			return
135		}
136		if a.costBasis != basis {
137			a.costBasis = usageCostBasisMixed
138		}
139	}
140	
141	func inferredUsageCostBasis(harness string, costUSD float64, basis string) string {
142		if costUSD <= 0 {
143			return ""
144		}
145		if isSubscriptionHarnessName(harness) {
146			return usageCostBasisEstimatedValue
147		}
148		if basis != "" {
149			return basis
150		}
151		return usageCostBasisEstimated
152	}
153	
154	func isSubscriptionHarnessName(harness string) bool {
155		switch strings.ToLower(harness) {
156		case "claude", "codex":
157			return true
158		default:
159			return false
160		}
161	}
162	
163	func applyUsageCostBasis(row *usageRow, isSubscription bool) {
164		if row == nil || row.CostUSD <= 0 {
165			return
166		}
167		if isSubscription {
168			row.CostBasis = usageCostBasisEstimatedValue
169			return
170		}
171		if row.CostBasis == "" {
172			row.CostBasis = usageCostBasisEstimated
173		}
174	}
175	
176	func (f *CommandFactory) newAgentUsageCommand() *cobra.Command {
177		cmd := &cobra.Command{
178			Use:   "usage",
179			Short: "Show per-harness token and cost summary",
180			Args:  cobra.NoArgs,
181			RunE: func(cmd *cobra.Command, args []string) error {
182				harness, _ := cmd.Flags().GetString("harness")
183				since, _ := cmd.Flags().GetString("since")
184				format, _ := cmd.Flags().GetString("format")
185	
186				sinceTime, err := parseSince(since)
187				if err != nil {
188					return fmt.Errorf("invalid --since value: %w", err)
189				}
190	
191				logDir := agent.SessionLogDirForWorkDir(f.WorkingDir)
192				rows, err := aggregateUsageFromRoutingMetrics(logDir, harness, sinceTime)
193				if err != nil {
194					return err
195				}
196				if len(rows) == 0 {
197					rows, err = aggregateUsageFromSessionIndex(logDir, harness, sinceTime, nil)
198				}
199				if err != nil {
200					return err
201				}
202				rows = enrichUsageRowsWithRoutingSignals(f.WorkingDir, rows)
203	
204				switch format {
205				case "json":
206					return renderUsageJSON(cmd, rows)
207				case "csv":
208					return renderUsageCSV(cmd, rows)
209				default:
210					return renderUsageTable(cmd, rows)
211				}
212			},
213		}
214	
215		cmd.Flags().String("harness", "", "Filter by harness name")
216		cmd.Flags().String("since", "30d", "Time window: today, 7d, 30d, or ISO date (e.g. 2026-04-01)")
217		cmd.Flags().String("format", "table", "Output format: table, json, csv")
218		return cmd
219	}
220	
221	// parseSince converts a --since string to a time.Time cutoff.
222	func parseSince(s string) (time.Time, error) {
223		switch s {
224		case "today":
225			now := time.Now()
226			return time.Date(now.Year(), now.Month(), now.Day(), 0, 0, 0, 0, now.Location()), nil
227		case "":
228			return time.Now().AddDate(0, 0, -30), nil
229		}
230		if strings.HasSuffix(s, "d") {
231			n, err := strconv.Atoi(strings.TrimSuffix(s, "d"))
232			if err != nil {
233				return time.Time{}, fmt.Errorf("expected Nd format, got %q", s)
234			}
235			return time.Now().AddDate(0, 0, -n), nil
236		}
237		// Try ISO date
238		t, err := time.Parse("2006-01-02", s)
239		if err != nil {
240			return time.Time{}, fmt.Errorf("unrecognized format %q, want today, Nd, or YYYY-MM-DD", s)
241		}
242		return t, nil
243	}
244	
245	// aggregateUsage reads the sharded session index and returns per-harness aggregates.
246	func aggregateUsage(logFile, harnessFilter string, since time.Time, mirrored map[string]struct{}) ([]usageRow, error) {
247		byHarness, order, err := aggregateUsageAggs(logFile, harnessFilter, since, nil, mirrored)
248		if err != nil {
249			return nil, err
250		}
251	
252		rows := make([]usageRow, 0, len(order))
253		for _, h := range order {
254			rows = append(rows, byHarness[h].toRow(h))
255		}
256		return rows, nil
257	}
258	
259	func aggregateUsageFromSessionIndex(logDir, harnessFilter string, since time.Time, mirrored map[string]struct{}) ([]usageRow, error) {
260		records, err := readUsageSessionIndexRecords(logDir, harnessFilter, since)
261		if err != nil {
262			return nil, err
263		}
264		byHarness := map[string]*usageAgg{}
265		order := []string{}
266		for _, record := range records {
267			if mirrored != nil && record.key != "" {
268				if _, ok := mirrored[record.key]; ok {
269					continue
270				}
271			}
272			a, exists := byHarness[record.entry.Harness]
273			if !exists {
274				a = &usageAgg{}
275				byHarness[record.entry.Harness] = a
276				order = append(order, record.entry.Harness)
277			}
278			a.addSession(record.entry)
279		}
280		rows := make([]usageRow, 0, len(order))
281		for _, h := range order {
282			rows = append(rows, byHarness[h].toRow(h))
283		}
284		return rows, nil
285	}
286	
287	// aggregateUsageAggs is the compatibility-aware session aggregator used by
288	// both the primary routing-store path and the legacy fallback path.
289	func aggregateUsageAggs(logFile, harnessFilter string, since time.Time, cutoffByHarness map[string]time.Time, mirrored map[string]struct{}) (map[string]*usageAgg, []string, error) {
290		byHarness := map[string]*usageAgg{}
291		order := []string{}
292	
293		err := agent.ForEachJSONL[agent.SessionEntry](logFile, func(entry agent.SessionEntry) error {
294			if entry.Timestamp.Before(since) {
295				return nil
296			}
297			if mirrored != nil {
298				if key := usageMirrorKey(entry.NativeSessionID, entry.TraceID, entry.SpanID); key != "" {
299					if _, ok := mirrored[key]; ok {
300						return nil
301					}
302				}
303			}
304			if cutoffByHarness != nil {
305				if cutoff, ok := cutoffByHarness[entry.Harness]; ok && !cutoff.IsZero() && !entry.Timestamp.Before(cutoff) {
306					return nil
307				}
308			}
309			if harnessFilter != "" && entry.Harness != harnessFilter {
310				return nil
311			}
312	
313			a, exists := byHarness[entry.Harness]
314			if !exists {
315				a = &usageAgg{}
316				byHarness[entry.Harness] = a
317				order = append(order, entry.Harness)
318			}
319			a.addSession(entry)
320			return nil
321		})
322		if err != nil {
323			return nil, nil, err
324		}
325	
326		return byHarness, order, nil
327	}
328	
329	// aggregateUsageFromRoutingMetrics prefers the minimal routing-outcome store
330	// and supplements it with legacy session rows that predate the first mirrored
331	// routing sample for each harness so mixed stores remain backward compatible
332	// without double counting current runs.
333	func aggregateUsageFromRoutingMetrics(logDir, harnessFilter string, since time.Time) ([]usageRow, error) {
334		store := agent.NewRoutingMetricsStore(logDir)
335		outcomes, err := store.ReadOutcomes()
336		if err != nil {
337			return nil, err
338		}
339		if len(outcomes) == 0 {
340			return nil, nil
341		}
342	
343		byHarness := map[string]*usageAgg{}
344		order := []string{}
345		mirrored := map[string]struct{}{}
346		cutoffByHarness := map[string]time.Time{}
347	
348		for _, outcome := range outcomes {
349			if key := usageMirrorKey(outcome.NativeSessionID, outcome.TraceID, outcome.SpanID); key != "" {
350				mirrored[key] = struct{}{}
351			}
352			if cutoff, ok := cutoffByHarness[outcome.Harness]; !ok || outcome.ObservedAt.Before(cutoff) {
353				cutoffByHarness[outcome.Harness] = outcome.ObservedAt
354			}
355			if outcome.ObservedAt.Before(since) {
356				continue
357			}
358			if harnessFilter != "" && outcome.Harness != harnessFilter {
359				continue
360			}
361	
362			a, exists := byHarness[outcome.Harness]
363			if !exists {
364				a = &usageAgg{}
365				byHarness[outcome.Harness] = a
366				order = append(order, outcome.Harness)
367			}
368			a.addOutcome(outcome)
369		}
370	
371		if len(order) == 0 {
372			return nil, nil
373		}
374	
375		sessionRecords, err := readUsageSessionIndexRecords(logDir, harnessFilter, since)
376		if err != nil {
377			return nil, err
378		}
379	
380		lastIndexByHarness := map[string]int{}
381		for i, record := range sessionRecords {
382			lastIndexByHarness[record.entry.Harness] = i
383		}
384	
385		skipCurrentRun := map[int]struct{}{}
386		for harness, idx := range lastIndexByHarness {
387			if _, ok := byHarness[harness]; !ok {
388				continue
389			}
390			if sessionRecords[idx].key == "" {
391				skipCurrentRun[idx] = struct{}{}
392			}
393		}
394	
395		for i, record := range sessionRecords {
396			if _, ok := skipCurrentRun[i]; ok {
397				continue
398			}
399			if record.key != "" {
400				if _, ok := mirrored[record.key]; ok {
401					continue
402				}
403			}
404			if cutoff, ok := cutoffByHarness[record.entry.Harness]; ok && !cutoff.IsZero() && !record.entry.Timestamp.Before(cutoff) {
405				continue
406			}
407	
408			a, exists := byHarness[record.entry.Harness]
