424	// enrichUsageRowsWithRoutingSignals annotates usage rows with per-harness
425	// routing signals from the upstream agent service. When the service is
426	// unavailable the rows are returned unchanged. Legacy DDx-managed file
427	// parsers were retired in ddx-7bc0c8d5.
428	func enrichUsageRowsWithRoutingSignals(workDir string, rows []usageRow) []usageRow {
429		svc, err := agent.NewServiceFromWorkDir(workDir)
430		if err != nil || svc == nil {
431			return rows
432		}
433		ctx := context.Background()
434		infos, err := svc.ListHarnesses(ctx)
435		if err != nil {
436			return rows
437		}
438		byName := make(map[string]agentlib.HarnessInfo, len(infos))
439		for _, info := range infos {
440			byName[info.Name] = info
441		}
442		now := time.Now()
443		for i := range rows {
444			info, ok := byName[rows[i].Harness]
445			if !ok {
446				continue
447			}
448			signal := harnessInfoToRoutingSignal(info, now)
449			applyUsageCostBasis(&rows[i], info.IsSubscription)
450			rows[i].QuotaState = signal.CurrentQuota.State
451			if signal.Provider == "" && signal.Source.Kind == "" {
452				continue
453			}
454			rows[i].SignalProvider = signal.Provider
455			rows[i].SignalKind = signal.Source.Kind
456			rows[i].SignalFreshness = signal.Source.Freshness
457			rows[i].SignalBasis = signal.Source.Basis
458			rows[i].NativeInputTokens = signal.HistoricalUsage.InputTokens
459			rows[i].NativeOutputTokens = signal.HistoricalUsage.OutputTokens
460			rows[i].NativeTotalTokens = signal.HistoricalUsage.TotalTokens
461			rows[i].NativeSessionCount = signal.HistoricalUsage.SessionCount
462			rows[i].NativeQuotaUsedPercent = signal.CurrentQuota.UsedPercent
463		}
464		return rows
465	}
