1338	func (f *CommandFactory) newAgentCatalogCommand() *cobra.Command {
1339		cmd := &cobra.Command{
1340			Use:   "catalog",
1341			Short: "Manage the model catalog (tier assignments)",
1342		}
1343	
1344		// catalog show: print current effective catalog.
1345		showCmd := &cobra.Command{
1346			Use:   "show",
1347			Short: "Show the current model catalog (tier→surface→model assignments)",
1348			RunE: func(cmd *cobra.Command, args []string) error {
1349				path := agent.DefaultModelCatalogPath()
1350				cat, err := agent.LoadModelCatalogYAML(path)
1351				if err != nil {
1352					return fmt.Errorf("load catalog: %w", err)
1353				}
1354				if cat == nil {
1355					cat = agent.DefaultModelCatalogYAML()
1356					fmt.Fprintf(cmd.OutOrStdout(), "(built-in defaults — no catalog at %s)\n\n", path)
1357				} else {
1358					fmt.Fprintf(cmd.OutOrStdout(), "Catalog: %s (updated %s)\n\n", path, cat.UpdatedAt.Format("2006-01-02"))
1359				}
1360	
1361				// Tiers
1362				for _, tier := range []string{"smart", "standard", "cheap"} {
1363					def, ok := cat.Tiers[tier]
1364					if !ok {
1365						continue
1366					}
1367					fmt.Fprintf(cmd.OutOrStdout(), "[%s] %s\n", tier, def.Description)
1368					for surface, model := range def.Surfaces {
1369						fmt.Fprintf(cmd.OutOrStdout(), "  %-20s %s\n", surface, model)
1370					}
1371				}
1372	
1373				// Blocked models
1374				var blocked []string
1375				for _, m := range cat.Models {
1376					if m.Blocked {
1377						blocked = append(blocked, m.ID)
1378					}
1379				}
1380				if len(blocked) > 0 {
1381					fmt.Fprintf(cmd.OutOrStdout(), "\nBlocked models (routing never selects these):\n")
1382					for _, id := range blocked {
1383						fmt.Fprintf(cmd.OutOrStdout(), "  %s\n", id)
1384					}
1385				}
1386	
1387				// Reachability warnings (ddx-5538aa5b AC#4): for each tier surface,
1388				// probe the agent service to see whether the catalog model resolves
1389				// to a healthy route. A tier with zero reachable surfaces would
1390				// produce "no viable provider" in execute-loop; surface that gap
1391				// here so users discover it before invoking the queue.
1392				projectFlag, _ := cmd.Flags().GetString("project")
1393				projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)
1394				svc, svcErr := agent.NewServiceFromWorkDir(projectRoot)
1395				if svcErr == nil && svc != nil {
1396					ctx := cmd.Context()
1397					if ctx == nil {
1398						ctx = context.Background()
1399					}
1400					var warnings []string
1401					for _, tier := range []string{"smart", "standard", "cheap"} {
1402						def, ok := cat.Tiers[tier]
1403						if !ok || len(def.Surfaces) == 0 {
1404							continue
1405						}
1406						anyReachable := false
1407						var perSurface []string
1408						for surface, model := range def.Surfaces {
1409							_, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{
1410								Model: model,
1411							})
1412							if err == nil {
1413								anyReachable = true
1414								break
1415							}
1416							perSurface = append(perSurface, fmt.Sprintf("    %s (%s): %v", surface, model, err))
1417						}
1418						if !anyReachable {
1419							warnings = append(warnings, fmt.Sprintf("  [%s] no surface resolves to a healthy route:\n%s", tier, strings.Join(perSurface, "\n")))
1420						}
1421					}
1422					if len(warnings) > 0 {
1423						fmt.Fprintf(cmd.OutOrStdout(), "\nWarning: tiers with no reachable provider:\n")
1424						for _, w := range warnings {
1425							fmt.Fprintln(cmd.OutOrStdout(), w)
1426						}
1427					}
1428				}
1429				return nil
1430			},
1431		}
1432		showCmd.Flags().String("project", "", "Project root (default: current directory)")
1433	
1434		cmd.AddCommand(showCmd)
1435		return cmd
1436	}
