678	// collectProviderSignalSources builds the signal_sources array from the snapshot and metrics presence.
679	// Defined values per FEAT-014: native-session-jsonl, stats-cache, ddx-metrics, none.
680	func collectProviderSignalSources(signal agent.RoutingSignalSnapshot, hasMetrics bool) []string {
681		seen := map[string]bool{}
682		result := []string{}
683		if signal.Source.Kind != "" {
684			if enum := signalSourceAPIEnum(signal.Source.Kind); enum != "none" {
685				seen[enum] = true
686				result = append(result, enum)
687			}
688		}
689		if hasMetrics && !seen["ddx-metrics"] {
690			result = append(result, "ddx-metrics")
691			seen["ddx-metrics"] = true
692		}
693		if len(result) == 0 {
694			result = []string{"none"}
695		}
696		return result
697	}
