699	// providerFreshnessTS returns the oldest contributing signal timestamp.
700	// Returns zero time when no signals exist (caller omits the field per FEAT-014).
701	func providerFreshnessTS(signal agent.RoutingSignalSnapshot, outcomes []agent.RoutingOutcome) time.Time {
702		var oldest time.Time
703		if !signal.Source.ObservedAt.IsZero() {
704			oldest = signal.Source.ObservedAt
705		}
706		for _, o := range outcomes {
707			if oldest.IsZero() || o.ObservedAt.Before(oldest) {
708				oldest = o.ObservedAt
709			}
710		}
711		return oldest
712	}
