12	// ModelCatalogYAML is the on-disk format for the model catalog.
13	// Stored at ~/.ddx/model-catalog.yaml.
14	// Drives tier→model assignments and pricing without requiring a rebuild.
15	type ModelCatalogYAML struct {
16		Version   int                    `yaml:"version"`
17		UpdatedAt time.Time              `yaml:"updated_at"`
18		Tiers     map[string]TierDefYAML `yaml:"tiers"`  // tier name → surface→model
19		Models    []ModelEntryYAML       `yaml:"models"` // per-model metadata and pricing
20	}
21	
22	// TierDefYAML maps surfaces to concrete model strings for a tier.
23	type TierDefYAML struct {
24		Description string            `yaml:"description"`
25		Surfaces    map[string]string `yaml:"surfaces"` // surface → concrete model
26	}
27	
28	// ModelEntryYAML holds metadata for one model.
29	type ModelEntryYAML struct {
30		ID       string `yaml:"id"` // e.g. "claude-sonnet-4-6"
31		Provider string `yaml:"provider"`
32		Tier     string `yaml:"tier"`              // smart, standard, cheap
33		Blocked  bool   `yaml:"blocked,omitempty"` // if true, routing never selects this model
34		Notes    string `yaml:"notes,omitempty"`
35	}
